SELECT AVG(price) AS average_price_per_click
FROM ad_performance
WHERE advertiser_id = 1;

SELECT COUNT(click_id) AS total_clicks
FROM clicks
WHERE performance_id = 1;

SELECT conversion_rate
FROM ad_performance
WHERE clicks > 0;

SELECT publisher_id
FROM ad_performance
ORDER BY publisher_id DESC;

SELECT clicks AS total_clicks
FROM ad_performance
WHERE performance_id = 1;

SELECT clicks
FROM ad_performance
WHERE performance_id = 0;
